 */
int test_reactive_calculation(int a, int b) {
    using namespace reaction;

    // Create reactive variables
    auto varA = var(a);
    auto varB = var(b);

    // Create a reactive calculation: (a + b) * 2
    auto calculation = calc([] (int x, int y) {
