Here's the complete implementation of the test function using the reaction library:

```cpp
#pragma once

#include <reaction/reaction.h>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test resetting a calculation node with new dependencies
 *
 * @param a First input value
 * @param b Second input value
 * @param c Third input value
 * @return int The result after resetting calculation to use different dependencies
 */
int test_calculation_reset(int a, int b, int c) {
    // 1. Create reactive variables
    reaction::Var<int> var_a(a);
    reaction::Var<int> var_b(b);
    reaction::Var<int> var_c(c);

    // 2. Create initial calculation (sum of a and b)
    reaction::Calc<int> calc_ab([&]() {
        return var_a.get() + var_b.get();
    });

    // Get initial result
    int initial_result = calc_ab.get();

    // 3. Reset calculation with different dependencies (sum of a and c)
    calc_ab.reset([&]() {
        return var_a.get() + var_c.get();
    });

    // 4. Return result after reset
    return calc_ab.get();
}

}  // namespace test_reaction
```

