    using CacheBase::get_stats;
};

GenericCacheStatsSnapshot test_generic_cache_base() {
    auto cache = std::make_unique<IntCache>();

    // Get initial cache statistics
    auto stats_before = cache->get_stats();
    std::size_t entriesBefore = stats_before.get_current_entries();

    // Perform initial lookup (should miss)
    int key = 42;
    auto result1 = cache->lookup(key);
    bool firstLookupWasMiss = (result1 == nullptr);

    // Insert value into cache
    int value = 100;
    cache->insert(key, value);

    // Perform second lookup (should hit)
    auto result2 = cache->lookup(key);
    bool secondLookupWasHit = (result2 != nullptr);

    // Get cache statistics after insertion
    auto stats_after_insert = cache->get_stats();
    std::size_t entriesAfterInsert = stats_after_insert.get_current_entries();

    // Invalidate all cache entries
    cache->invalidate_all();

    // Trigger cleanup
    cache->cleanup();

    // Get cache statistics after invalidation
    auto stats_after_invalidate = cache->get_stats();
    std::size_t entriesAfterInvalidate = stats_after_invalidate.get_current_entries();

    // Calculate hit ratio
    std::size_t hitCount = stats_after_invalidate.get_hit_count();
    std::size_t missCount = stats_after_invalidate.get_miss_count();
    double hitRatio = (hitCount + missCount > 0) ? 
        static_cast<double>(hitCount) / (hitCount + missCount) : 0.0;

    return GenericCacheStatsSnapshot{
        entriesBefore,
        entriesAfterInsert,
        entriesAfterInvalidate,
        hitCount,
        missCount,
        hitRatio,
        firstLookupWasMiss,
        secondLookupWasHit
    };
}

