    auto sumExpr = reaction::make_binary_expr(varA, varB, std::plus<int>{});

    // 3. Build negated expression: -(A + B)
    auto negatedExpr = reaction::make_unary_expr(sumExpr, std::negate<int>{});

    // 4. Build chained expression: -(A + B) * C
    auto chainedExpr = reaction::make_binary_expr(negatedExpr, varC, std::multiplies<int>{});

    // 5. Get initial expression values
    RawExpressionSnapshot snapshot;
    snapshot.initialSum = reaction::expr(sumExpr).value();
    snapshot.initialNegatedSum = reaction::expr(negatedExpr).value();
    snapshot.initialChainedValue = reaction::expr(chainedExpr).value();

    // 6. Update variables to trigger recomputation
    varA.set(a + 10);
    varC.set(c * 3);

    // 7. Get updated expression values
    snapshot.updatedSum = reaction::expr(sumExpr).value();
    snapshot.updatedNegatedSum = reaction::expr(negatedExpr).value();
    snapshot.updatedChainedValue = reaction::expr(chainedExpr).value();

    // 8. Return raw expression snapshot
    return snapshot;
}

}  // namespace test_reaction

